1	import { join } from 'path'
2	import fse from 'fs-extra'
3	import {
4	  scanAssignments,
5	  readProcessedCaptures,
6	  readKnowledgeBranch,
7	} from '../utils/scan.js'
8	import {
9	  resolveTargetDir,
10	  requireSpecdevDirectory,
11	} from '../utils/command-context.js'
12	
13	const KNOWLEDGE_BRANCHES = ['codestyle', 'architecture', 'domain', 'workflow']
14	const BIG_PICTURE_WORD_LIMIT = 2000
15	
16	export async function distillCommand(flags = {}) {
17	  const targetDir = resolveTargetDir(flags)
18	  const specdevPath = join(targetDir, '.specdev')
19	  await requireSpecdevDirectory(specdevPath)
20	
21	  if (typeof flags.assignment !== 'string' || !flags.assignment.trim()) {
22	    console.error('Missing required --assignment flag')
23	    console.log('Usage: specdev distill --assignment=<name>')
24	    process.exitCode = 1
25	    return
26	  }
27	
28	  const wanted = flags.assignment.trim()
29	  const knowledgePath = join(specdevPath, 'knowledge')
30	
31	  const assignments = await scanAssignments(specdevPath)
32	  const match = assignments.find(a => a.name === wanted)
33	
34	  if (!match) {
35	    console.log(JSON.stringify({
36	      status: 'error',
37	      error: `Assignment not found: ${wanted}`,
38	    }, null, 2))
39	    process.exitCode = 1
40	    return
41	  }
42	
43	  // Read capture diffs
44	  const capturePath = join(match.path, 'capture')
45	  let projectNotesDiff = null
46	  let workflowDiff = null
47	
48	  const pndPath = join(capturePath, 'project-notes-diff.md')
49	  if (await fse.pathExists(pndPath)) {
50	    projectNotesDiff = await fse.readFile(pndPath, 'utf-8')
51	  }
52	
53	  const wdPath = join(capturePath, 'workflow-diff.md')
54	  if (await fse.pathExists(wdPath)) {
55	    workflowDiff = await fse.readFile(wdPath, 'utf-8')
56	  }
57	
58	  if (!projectNotesDiff && !workflowDiff) {
59	    console.log(JSON.stringify({
60	      status: 'no_captures',
61	      assignment: wanted,
62	      capture: { project_notes_diff: null, workflow_diff: null },
63	    }, null, 2))
64	    return
65	  }
66	
67	  // Read existing knowledge file listings
68	  const knowledgeFiles = {}
69	  for (const branch of KNOWLEDGE_BRANCHES) {
70	    const entries = await readKnowledgeBranch(knowledgePath, branch)
71	    knowledgeFiles[branch] = entries.map(e => e.file)
72	  }
73	
74	  // Workflow feedback files
75	  const feedbackDir = join(knowledgePath, 'workflow_feedback')
76	  let feedbackFiles = []
77	  if (await fse.pathExists(feedbackDir)) {
78	    feedbackFiles = (await fse.readdir(feedbackDir))
79	      .filter(f => f.endsWith('.md') && !f.startsWith('.'))
80	  }
81	  knowledgeFiles.workflow_feedback = feedbackFiles
82	
83	  // Read big_picture word count
84	  const bigPicturePath = join(specdevPath, 'project_notes', 'big_picture.md')
85	  let bigPictureWordCount = 0
86	  if (await fse.pathExists(bigPicturePath)) {
87	    const content = await fse.readFile(bigPicturePath, 'utf-8')
88	    bigPictureWordCount = content.split(/\s+/).filter(Boolean).length
89	  }
90	
91	  // Generate heuristics (combined project + workflow)
92	  const processed = await readProcessedCaptures(knowledgePath, 'project')
93	  const unprocessed = assignments.filter(a => !processed.has(a.name))
94	  const heuristics = [
95	    ...generateProjectHeuristics(unprocessed, knowledgeFiles),
96	    ...generateWorkflowHeuristics(unprocessed),
97	  ]
98	
99	  const output = {
100	    status: 'ok',
101	    assignment: wanted,
102	    capture: {
103	      project_notes_diff: projectNotesDiff,
104	      workflow_diff: workflowDiff,
105	    },
106	    knowledge_files: knowledgeFiles,
107	    big_picture_path: '.specdev/project_notes/big_picture.md',
108	    big_picture_word_count: bigPictureWordCount,
109	    big_picture_word_limit: BIG_PICTURE_WORD_LIMIT,
110	    heuristics,
111	  }
112	
113	  console.log(JSON.stringify(output, null, 2))
114	}
115	
116	function generateProjectHeuristics(assignments, existingKnowledge) {
117	  const suggestions = []
118	
119	  const typeCounts = {}
120	  for (const a of assignments) {
121	    if (a.type) {
122	      typeCounts[a.type] = (typeCounts[a.type] || 0) + 1
123	    }
124	  }
125	
126	  for (const [type, count] of Object.entries(typeCounts)) {
127	    if (count >= 2) {
128	      suggestions.push({
129	        title: `Recurring ${type} assignments`,
130	        body: `${count} "${type}" assignments found. Consider documenting common patterns.`,
131	        source: 'heuristic',
132	        assignments: assignments.filter(a => a.type === type).map(a => a.name),
133	      })
134	    }
135	  }
136	
137	  const withDecisions = assignments.filter(a => a.context && a.context.hasDecisions)
138	  if (withDecisions.length > 0 && existingKnowledge.architecture.length === 0) {
139	    suggestions.push({
140	      title: 'Capture architectural decisions',
141	      body: `${withDecisions.length} assignment(s) contain decisions but no architecture knowledge exists.`,
142	      source: 'heuristic',
143	      assignments: withDecisions.map(a => a.name),
144	    })
145	  }
146	
147	  if (assignments.length >= 3 && existingKnowledge.codestyle.length === 0) {
148	    suggestions.push({
149	      title: 'Document code style patterns',
150	      body: `${assignments.length} assignments completed but no codestyle knowledge documented.`,
151	      source: 'heuristic',
152	      assignments: assignments.map(a => a.name),
153	    })
154	  }
155	
156	  const domainRelated = assignments.filter(a => a.label && a.label.length > 0)
157	  if (domainRelated.length >= 2 && existingKnowledge.domain.length === 0) {
158	    suggestions.push({
159	      title: 'Capture domain concepts',
160	      body: `Assignments reference domain areas but no domain knowledge documented.`,
161	      source: 'heuristic',
162	      assignments: domainRelated.map(a => a.name),
163	    })
164	  }
165	
166	  return suggestions
167	}
168	
169	function generateWorkflowHeuristics(assignments) {
170	  const suggestions = []
171	
172	  const skippedPhaseCounts = {}
173	  for (const a of assignments) {
174	    for (const phase of a.skippedPhases) {
175	      skippedPhaseCounts[phase] = (skippedPhaseCounts[phase] || 0) + 1
176	    }
177	  }
178	
179	  for (const [phase, count] of Object.entries(skippedPhaseCounts)) {
180	    if (count >= 2) {
181	      suggestions.push({
182	        title: `${phase} phase frequently skipped`,
183	        body: `The "${phase}" phase was skipped in ${count} assignments.`,
184	        source: 'heuristic',
185	        assignments: assignments.filter(a => a.skippedPhases.includes(phase)).map(a => a.name),
186	      })
187	    }
188	  }
189	
190	  const noContext = assignments.filter(a => !a.context)
191	  if (noContext.length > 0) {
192	    suggestions.push({
193	      title: 'Assignments missing context tracking',
194	      body: `${noContext.length} assignment(s) have no context/ directory.`,
195	      source: 'heuristic',
196	      assignments: noContext.map(a => a.name),
197	    })
198	  }
199	
200	  const highMessages = assignments.filter(a => a.context && a.context.messageCount > 5)
201	  if (highMessages.length > 0) {
202	    suggestions.push({
203	      title: 'High inter-agent message volume',
204	      body: `${highMessages.length} assignment(s) had more than 5 inter-agent messages.`,
205	      source: 'heuristic',
206	      assignments: highMessages.map(a => a.name),
207	    })
208	  }
209	
210	  return suggestions
211	}
