1	export function parseArgv(argv) {
2	  const [, , command, ...args] = argv
3	  const flags = {}
4	  const positionalArgs = []
5	
6	  args.forEach((arg) => {
7	    if (arg.startsWith('--')) {
8	      const equalIndex = arg.indexOf('=')
9	      if (equalIndex > -1) {
10	        const key = arg.slice(2, equalIndex)
11	        const value = arg.slice(equalIndex + 1)
12	        flags[key] = value
13	      } else {
14	        flags[arg.slice(2)] = true
15	      }
16	      return
17	    }
18	
19	    if (arg.startsWith('-')) {
20	      flags[arg.slice(1)] = true
21	      return
22	    }
23	
24	    positionalArgs.push(arg)
25	  })
26	
27	  return { command, flags, positionalArgs }
28	}
